import java.util.Scanner;
import org.owasp.esapi.ESAPI;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        name = ESAPI.encoder().encodeForHTML(name); // Sanitize user input

        System.out.println("Hello, " + name + "!");

        System.out.println("Redirecting to the user's profile page...");
        // Safely include user input in HTML attribute
        System.out.println("<a href='http://www.example.com/user/" + name + "'>Visit my profile</a>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
